// Format message with severity icons and structure
const input = $input.first().json;

const title = input.title || 'System Notification';
const message = input.message || '';
const severity = (input.severity || 'info').toLowerCase();
let channels = [];
try {
  channels = typeof input.channels === 'string' ? JSON.parse(input.channels) : (input.channels || ['matrix']);
} catch (e) {
  channels = ['matrix'];
}

const SEVERITY_ICONS = {
  info: 'ℹ️',
  warning: '⚠️',
  critical: '🚨',
  error: '❌',
  success: '✅'
};

const icon = SEVERITY_ICONS[severity] || 'ℹ️';
const timestamp = new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

// Matrix-formatted message (supports markdown)
const matrixBody = `${icon} **${title}**\n\n${message}\n\n_${timestamp}_`;
const matrixFormattedBody = `<strong>${icon} ${title}</strong><br><br>${message.replace(/\n/g, '<br>')}<br><br><em>${timestamp}</em>`;

// Telegram message (simpler formatting)
const telegramText = `${icon} *${title}*\n\n${message}\n\n_${timestamp}_`;

return [{
  json: {
    title,
    message,
    severity,
    channels,
    icon,
    timestamp,
    matrix_body: matrixBody,
    matrix_formatted_body: matrixFormattedBody,
    telegram_text: telegramText,
    send_to_matrix: channels.includes('matrix'),
    send_to_telegram: channels.includes('telegram'),
    notification_id: `notif_${Date.now()}`
  }
}];

// Collect notification results from all channels
const allItems = $input.all();
const formatData = $('🔧 Format Message').first().json;

const sentChannels = [];
const failedChannels = [];

// Check Matrix result
if (formatData.send_to_matrix) {
  try {
    const matrixResult = $('📨 Matrix: Send Message').first().json;
    if (matrixResult.event_id || !matrixResult.error) {
      sentChannels.push('matrix');
    } else {
      failedChannels.push('matrix');
    }
  } catch (e) {
    // Node may not have run if routing skipped it
    if (formatData.send_to_matrix) failedChannels.push('matrix');
  }
}

// Check Telegram result
if (formatData.send_to_telegram) {
  try {
    const telegramResult = $('📨 Telegram: Send Message').first().json;
    if (telegramResult.ok === true) {
      sentChannels.push('telegram');
    } else {
      failedChannels.push('telegram');
    }
  } catch (e) {
    if (formatData.send_to_telegram) failedChannels.push('telegram');
  }
}

const status = failedChannels.length === 0 ? 'sent' : (sentChannels.length > 0 ? 'partial' : 'failed');

return [{
  json: {
    notification_id: formatData.notification_id,
    sent_channels: sentChannels,
    failed_channels: failedChannels,
    status,
    title: formatData.title,
    severity: formatData.severity,
    sent_at: formatData.timestamp
  }
}];
